steps.script:
var main = tree.get_current_scene()
var bw = GameState.state.units["U_BATTLEWAGON_G"]
var owner = int(bw.get("owner", 2))
GameState.state.units["U_BATTLEWAGON_G"]["status"] = GameStateData.UnitStatus.UNDEPLOYED
GameState.set_active_player(owner)
main.current_phase = GameStateData.Phase.DEPLOYMENT
main.refresh_unit_list()
var il = main.unit_list
var bw_idx = -1
for i in range(il.get_item_count()):
	var md = il.get_item_metadata(i)
	if md is String and md == "U_BATTLEWAGON_G":
		bw_idx = i
		break
if bw_idx == -1:
	return "FAIL: battlewagon not in undeployed list"
var saw_carrying = false
var saw_kommandos = false
for i in range(bw_idx + 1, il.get_item_count()):
	var md = il.get_item_metadata(i)
	if not (md is Dictionary and md.get("_subrow", false)):
		break
	var t = str(il.get_item_text(i))
	if t.find("Carrying") != -1:
		saw_carrying = true
	if t.find("Kommandos") != -1 and t.find("10") != -1:
		saw_kommandos = true
if saw_carrying and saw_kommandos:
	return "PASS_LIST"
return "FAIL: carrying=%s kommandos=%s" % [str(saw_carrying), str(saw_kommandos)]

var main = tree.get_current_scene()
main.show_unit_card("U_BATTLEWAGON_G")
var lbl = main.transport_contents_label
if lbl == null:
	return "FAIL: no transport_contents_label node"
if not lbl.visible:
	return "FAIL: label not visible for transport"
var t = str(lbl.text)
if t.find("Carrying") != -1 and t.find("Kommandos") != -1 and t.find("10") != -1:
	return "PASS_CARD"
return "FAIL: card text=" + t

var main = tree.get_current_scene()
main.show_unit_card("U_KOMMANDOS_H")
return main.transport_contents_label.visible
